const tasks = $input.all().map(function(i){ return i.json; }).filter(function(j){ return j && Object.keys(j).length>0; });
const admins = $('Fetch Admins').all().map(function(i){ return i.json||{}; });
function norm(p){ var d=String(p||'').replace(/[^0-9]/g,'').slice(-10); if(d.length===10){ d='91'+d; } return d; }
var adminPhone = admins.length ? norm(admins[0].phoneLast10||admins[0].phone) : '919601775061';
var now = Date.now();
var out = [];
tasks.forEach(function(t){
  var status = String(t.status||'').toLowerCase();
  if (['done','closed','completed','cancelled'].indexOf(status)!==-1) { return; }
  var created = t.createdAt ? new Date(t.createdAt).getTime() : now;
  var ageDays = (now-created)/86400000;
  var lastR = t.lastReminderAt ? new Date(t.lastReminderAt).getTime() : 0;
  var hrs = lastR ? (now-lastR)/3600000 : 999;
  var updatedT = t.updatedAt ? new Date(t.updatedAt).getTime() : 0;
  var count = parseInt(t.reminderCount||0,10)||0;
  var title = t.title || t.details || ('task '+(t.taskId||''));
  var assignee = norm(t.assigneePhone);
  if (lastR && updatedT > lastR) {
    out.push({ json: { taskId: String(t.taskId||''), recipientPhone: '', message: '', reminderCount: 0, lastReminderAt: new Date().toISOString(), escalated: false } });
    return;
  }
  var due = false;
  if (ageDays < 1) { due = hrs >= 20; }
  else if (ageDays < 2) { due = hrs >= 8; }
  else { due = hrs >= 1; }
  if (!due) { return; }
  var to, msg;
  if (assignee.length >= 11 && ageDays < 3) {
    to = assignee;
    msg = 'Reminder: your task "' + title + '" is still open (day ' + (Math.floor(ageDays)+1) + '). Please reply with an update - in progress, done, or any issue.';
  } else {
    to = adminPhone;
    if (assignee.length >= 11) { msg = 'Task "' + title + '" assigned to ' + (t.assigneeName||assignee) + ' is still open after ' + Math.floor(ageDays) + ' days with no completion. Please contact them directly.'; }
    else { msg = 'UNASSIGNED open ticket (day ' + (Math.floor(ageDays)+1) + '): "' + title + '" ' + (t.clientName?('for '+t.clientName):'') + '. Please assign it to someone.'; }
  }
  out.push({ json: { taskId: String(t.taskId||''), recipientPhone: to, message: msg, reminderCount: count+1, lastReminderAt: new Date().toISOString(), escalated: (to===adminPhone) } });
});
return out;

// Reminders addressed to the assignee stay one-to-one; only escalations go to every admin.
const items = $input.all().map(function (i) { return i.json || {}; });
let admins = [];
try { admins = $('Fetch Admins').all().map(function (i) { return i.json || {}; }); } catch (e) { admins = []; }
function norm(p) { return String(p || '').replace(/[^0-9]/g, '').slice(-10); }
const seen = {};
const targets = [];
for (const a of admins) {
  if (!a || a.isActive === false || a.active === false) continue;
  if (a.notifyEnquiries !== true) continue;   // admins opt in; the rest keep their rights
  const p = norm(a.phoneLast10 || a.phone || a.phoneNumber);
  if (p.length !== 10 || seen[p]) continue;
  seen[p] = true;
  targets.push({ phone: '91' + p, name: a.name || '' });
}
if (!targets.length) targets.push({ phone: '919601775061', name: 'CGPE Admin' });
const out = [];
for (const it of items) {
  if (!it.escalated) { out.push({ json: it }); continue; }
  for (const t of targets) out.push({ json: Object.assign({}, it, { recipientPhone: t.phone, adminName: t.name }) });
}
return out;
